@import play.twirl.api.Html
@import org.owasp.html.PolicyFactory
@import org.owasp.html.HtmlPolicyBuilder

@(post: models.BlogPost)

@sanitize(untrustedHtml: String) = @{
    val policy: PolicyFactory = new HtmlPolicyBuilder()
        .allowElements("b", "i", "u", "em", "strong", "a", "p", "br", "ul", "ol", "li", "img", "h1", "h2", "h3", "h4", "h5", "h6", "blockquote", "pre", "code", "span", "div")
        .allowUrlProtocols("https", "http")
        .allowAttributes("href").onElements("a")
        .allowAttributes("src", "alt", "width", "height").onElements("img")
        .allowAttributes("class").onElements("span", "div", "p")
        .requireRelNofollowOnLinks()
        .toFactory()

    Html(policy.sanitize(untrustedHtml))
}

<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta http-equiv="Content-Security-Policy" content="default-src 'self'; img-src 'self' https:; style-src 'self'; script-src 'self'">
    <title>@post.title</title>
    <link rel="stylesheet" href="@routes.Assets.versioned("stylesheets/main.css")">
</head>
<body>
    <article class="blog-post">
        <header>
            <h1>@post.title</h1>
            <div class="post-meta">
                <span class="author">By @post.authorName</span>
                <time datetime="@post.publishedAt">@post.publishedAt.format("MMMM dd, yyyy")</time>
            </div>
        </header>

        <div class="post-content">
            @sanitize(post.htmlContent)
        </div>

        <footer class="post-footer">
            <div class="tags">
                @for(tag <- post.tags) {
                    <span class="tag">@tag</span>
                }
            </div>
        </footer>
    </article>
</body>
</html>